let scrollbar=document.querySelector(".scrollbar__list"),main=document.querySelector(".main"),thumbSelect=!0,scrolling=new IntersectionObserver(r=>{r.forEach(e=>{if(.5<=e.intersectionRatio){for(let r=0;r<main.children.length;r++)main.children[r]==e.target?scrollbar.children[r].style="--opacity-marker: 0; --opacity-text: 1":scrollbar.children[r].style="";thumbSelect=!1}else e.intersectionRatio<=.5&&(thumbSelect=!0)})},{root:main,threshold:.5});Array.from(main.children).forEach(r=>scrolling.observe(r)),Array.from(scrollbar.children).forEach(r=>r.onclick=e=>{for(let r=0;r<scrollbar.children.length;r++)scrollbar.children[r]==e.target&&main.children[r].scrollIntoView({behavior:"smooth"})});